import{_ as d,o as e,c as o,a2 as r}from"./chunks/framework.ChW7XBuO.js";const b=JSON.parse('{"title":"兼容性","description":"rolebox 与其他工具和框架的兼容性说明","frontmatter":{"title":"兼容性","description":"rolebox 与其他工具和框架的兼容性说明"},"headers":[],"relativePath":"04-Advanced/compatibility.md","filePath":"04-Advanced/compatibility.md"}'),a={name:"04-Advanced/compatibility.md"};function l(i,t,n,s,c,h){return e(),o("div",null,[...t[0]||(t[0]=[r(`<h1 id="兼容性" tabindex="-1">兼容性 <a class="header-anchor" href="#兼容性" aria-label="Permalink to &quot;兼容性&quot;">​</a></h1><p>rolebox 设计为与现有 opencode 生态协同工作，不做破坏性变更。</p><blockquote><p><strong>相关文档：</strong> <a href="/rolebox-docs/02-Guide/getting-started.html">快速入门</a> — 安装与配置指南 | <a href="/rolebox-docs/03-Reference/limitations.html">已知限制</a> — 当前版本的功能边界</p></blockquote><h2 id="与-oh-my-openagent-共存" tabindex="-1">与 oh-my-openagent 共存 <a class="header-anchor" href="#与-oh-my-openagent-共存" aria-label="Permalink to &quot;与 oh-my-openagent 共存&quot;">​</a></h2><p>rolebox 与 <a href="https://github.com/code-yeongyu/oh-my-openagent" target="_blank" rel="noreferrer">oh-my-openagent</a> (omo) 可以同时运行，互不冲突：</p><ul><li>rolebox 角色出现在 opencode 代理列表中，与 omo 代理并列</li><li>rolebox 技能可通过 opencode 的 <code>skill</code> 工具发现和加载</li><li>4 个同名会话工具（<code>session_list</code>、<code>session_read</code>、<code>session_search</code>、<code>session_info</code>）为增强版但向后兼容</li><li>其余 6 个会话工具使用 <code>session_</code> 前缀命名空间，不会与任何其他工具冲突</li></ul><h2 id="opencode-版本兼容性" tabindex="-1">opencode 版本兼容性 <a class="header-anchor" href="#opencode-版本兼容性" aria-label="Permalink to &quot;opencode 版本兼容性&quot;">​</a></h2><table tabindex="0"><thead><tr><th>rolebox 版本</th><th>opencode 最低版本</th><th>说明</th></tr></thead><tbody><tr><td>v0.17.x</td><td>≥1.3.0</td><td>完整功能支持（记忆系统、会话工具、Hashline 编辑）</td></tr><tr><td>v0.16.x</td><td>≥1.2.0</td><td>核心功能（角色调度、技能、函数）</td></tr><tr><td>v0.15.x</td><td>≥1.0.0</td><td>基本角色系统</td></tr></tbody></table><p>rolebox 通过 <code>@opencode-ai/plugin</code> SDK 与 opencode 通信，插件接口的向后兼容性由 opencode 团队维护。</p><h2 id="功能兼容性矩阵" tabindex="-1">功能兼容性矩阵 <a class="header-anchor" href="#功能兼容性矩阵" aria-label="Permalink to &quot;功能兼容性矩阵&quot;">​</a></h2><p>以下矩阵映射 rolebox 各版本引入的主要功能领域及其对应的 opencode 版本要求。版本阈值来源于 <a href="https://github.com/EricMoin/rolebox/blob/main/CHANGELOG.md" target="_blank" rel="noreferrer">CHANGELOG</a> 和 <code>package.json</code> 中的引擎声明。</p><table tabindex="0"><thead><tr><th>功能领域</th><th>引入版本</th><th>opencode 要求</th><th>关键依赖</th></tr></thead><tbody><tr><td>角色 YAML 系统</td><td>v0.1.0</td><td>≥1.0.0</td><td>—</td></tr><tr><td>Functions 函数系统 (plan/execute)</td><td>v0.2.0</td><td>≥1.0.0</td><td>—</td></tr><tr><td>CLI 工具链 (init/sync/search/list/update/registry)</td><td>v0.4.0</td><td>≥1.0.0</td><td>—</td></tr><tr><td>子代理系统 (dispatch/output/cancel)</td><td>v0.5.1</td><td>≥1.0.0</td><td>—</td></tr><tr><td>References 与 Collaboration Graph</td><td>v0.6.0</td><td>≥1.0.0</td><td>—</td></tr><tr><td>Dispatch 调度引擎 (事件驱动、并发隔离、持久化)</td><td>v0.10.0</td><td>≥1.0.0</td><td>—</td></tr><tr><td>Monitor 监控面板</td><td>v0.11.0</td><td>≥1.0.0</td><td>—</td></tr><tr><td>Loop 循环迭代系统</td><td>v0.14.0</td><td>≥1.0.0</td><td>—</td></tr><tr><td>LSP 语言服务器集成 (30+ 工具)</td><td>v0.17.0</td><td>≥1.3.0</td><td><code>@opencode-ai/plugin</code> SDK ≥1.3.0</td></tr><tr><td>会话管理 (session_list/read/search/info/diff/fork)</td><td>v0.17.0</td><td>≥1.3.0</td><td><code>@opencode-ai/plugin</code> SDK ≥1.3.0</td></tr><tr><td>Hashline 内容哈希编辑</td><td>v0.17.0</td><td>≥1.3.0</td><td><code>@opencode-ai/plugin</code> SDK ≥1.3.0</td></tr><tr><td>模型重复预防</td><td>v0.18.0</td><td>≥1.3.0</td><td>—</td></tr><tr><td>扩展系统与自定义 Hook</td><td>v0.19.0</td><td>≥1.3.0</td><td>—</td></tr><tr><td>错误恢复框架 (7+ 策略)</td><td>v0.19.0</td><td>≥1.3.0</td><td>—</td></tr><tr><td>通知管理器 (多通道、静默时段)</td><td>v0.19.0</td><td>≥1.3.0</td><td>—</td></tr><tr><td>持久记忆系统 (SQLite + FTS5)</td><td>v0.20.0</td><td>≥1.3.0</td><td><strong>Bun</strong> (bun:sqlite)</td></tr><tr><td>微内核架构与热重载</td><td>v0.20.0</td><td>≥1.3.0</td><td>—</td></tr><tr><td>Token/成本预算管理</td><td>v0.20.0</td><td>≥1.3.0</td><td>—</td></tr><tr><td>TUI 仪表板 (rolebox monitor)</td><td>v0.20.0</td><td>≥1.3.0</td><td>Solid.js + OpenTU</td></tr><tr><td>崩溃恢复 (降级启动)</td><td>v0.21.0</td><td>≥1.3.0</td><td>—</td></tr><tr><td>Asset 工具套件 (search/inspect/validate)</td><td>v0.21.0</td><td>≥1.3.0</td><td>—</td></tr><tr><td>Context Assembly 跨域搜索</td><td>v0.21.0</td><td>≥1.3.0</td><td>—</td></tr><tr><td>web_fetch / web_read (多后端渲染)</td><td>v0.22.0</td><td>≥1.3.0</td><td>Playwright / Crawlee (可选)</td></tr><tr><td>Signal 带外控制信号</td><td>v0.22.0</td><td>≥1.3.0</td><td>—</td></tr><tr><td>Dispatch 检查点与进度报告</td><td>v0.23.0</td><td>≥1.3.0</td><td>—</td></tr><tr><td>TUI 鼠标交互、指标面板</td><td>v0.23.0</td><td>≥1.3.0</td><td>Solid.js + OpenTU</td></tr></tbody></table><blockquote><p>来源：<code>../rolebox/CHANGELOG.md</code> — 每项功能的引入版本；<code>../rolebox/package.json:5-7</code> — <code>engines.opencode</code> 声明为 <code>^1.0.0</code>；<code>../rolebox/package.json:77</code> — <code>peerDependencies[&#39;@opencode-ai/plugin&#39;]</code> 声明为 <code>^1.3.0</code>。</p></blockquote><h2 id="破坏性变更摘要" tabindex="-1">破坏性变更摘要 <a class="header-anchor" href="#破坏性变更摘要" aria-label="Permalink to &quot;破坏性变更摘要&quot;">​</a></h2><p>以下表格汇总了 rolebox 各版本引入的破坏性变更，帮助用户在升级前评估影响范围。版本信息来源于 <a href="https://github.com/EricMoin/rolebox/blob/main/CHANGELOG.md" target="_blank" rel="noreferrer">CHANGELOG</a>。</p><table tabindex="0"><thead><tr><th>版本</th><th>变更类型</th><th>所需操作</th></tr></thead><tbody><tr><td>v0.23.0</td><td>TUI 键盘交互移除</td><td>改用鼠标点击操作；原有键盘快捷键更新为 <code>Ctrl+</code> 前缀以避免冲突</td></tr><tr><td>v0.20.0</td><td>运行时依赖变更</td><td>安装 <strong>Bun ≥1.1.0</strong>——持久记忆系统依赖于 <code>bun:sqlite</code>，无法在纯 Node.js 环境下运行</td></tr><tr><td>v0.17.0</td><td>核心依赖升级</td><td>更新 <code>peerDependencies</code>：opencode ≥1.3.0，<code>@opencode-ai/plugin</code> 升级至 <code>^1.3.0</code></td></tr><tr><td>v0.15.0</td><td>Loop 语义重写</td><td>\`</td></tr><tr><td>v0.12.0</td><td>状态存储迁移</td><td>状态存储路径从 <code>XDG_DATA_HOME</code> 变更为项目本地 <code>.rolebox/</code> 目录；旧数据需手动迁移</td></tr><tr><td>v0.10.0</td><td>Dispatch 调度系统重写</td><td>旧的全局轮询模式被 <code>TaskWatchdogManager</code> 取代；建议清空旧的 <code>.rolebox/state/</code> 状态文件</td></tr></tbody></table><blockquote><p>来源：<code>../rolebox/CHANGELOG.md</code> — 各版本的破坏性变更记录。非破坏性版本（v0.16.x、v0.18.x、v0.19.x、v0.21.x、v0.22.x）不在此表列出。</p></blockquote><h3 id="兼容性变更与功能限制关联" tabindex="-1">兼容性变更与功能限制关联 <a class="header-anchor" href="#兼容性变更与功能限制关联" aria-label="Permalink to &quot;兼容性变更与功能限制关联&quot;">​</a></h3><table tabindex="0"><thead><tr><th>破坏性变更</th><th>关联限制</th><th>说明</th></tr></thead><tbody><tr><td>v0.23.0 TUI 键盘→鼠标</td><td>—</td><td>交互变更，不涉及底层功能限制</td></tr><tr><td>v0.20.0 Bun 运行时依赖</td><td><a href="/rolebox-docs/04-Advanced/memory-system.html">持久记忆系统</a> 依赖 <code>bun:sqlite</code></td><td>详见<a href="/rolebox-docs/04-Advanced/compatibility.html#bun-vs-node-js">兼容性 → Bun vs Node.js</a></td></tr><tr><td>v0.17.0 opencode ≥1.3.0</td><td><a href="/rolebox-docs/03-Reference/limitations.html#子代理嵌套深度上限">子代理嵌套深度上限</a> 3 层</td><td>SDK 升级，子代理模型不受影响</td></tr><tr><td>v0.15.0 Loop 语义重写</td><td><a href="/rolebox-docs/04-Advanced/loop-system.html">循环系统</a> 9 阶段状态机</td><td>Loop 重启后自动恢复</td></tr><tr><td>v0.12.0 状态迁移 <code>.rolebox/</code></td><td><a href="/rolebox-docs/03-Reference/limitations.html#无运行时角色切换">无运行时角色切换</a></td><td>状态文件路径变更，角色模型不变</td></tr><tr><td>v0.10.0 Dispatch 重写</td><td><a href="/rolebox-docs/03-Reference/limitations.html#调度系统dispatch">调度并发限制</a></td><td>事件驱动架构，新增模型并发槽位</td></tr></tbody></table><h2 id="平台支持" tabindex="-1">平台支持 <a class="header-anchor" href="#平台支持" aria-label="Permalink to &quot;平台支持&quot;">​</a></h2><table tabindex="0"><thead><tr><th>平台</th><th>状态</th><th>说明</th></tr></thead><tbody><tr><td>macOS</td><td>完整支持</td><td>主开发平台</td></tr><tr><td>Linux</td><td>完整支持</td><td>CI 验证</td></tr><tr><td>Windows</td><td>基本支持</td><td>部分路径处理可能有差异；欢迎报告问题</td></tr></tbody></table><h2 id="运行时依赖" tabindex="-1">运行时依赖 <a class="header-anchor" href="#运行时依赖" aria-label="Permalink to &quot;运行时依赖&quot;">​</a></h2><p>rolebox 对运行时环境的最低要求：</p><ul><li><strong>Bun</strong> ≥1.1.0（用于 <code>bun:sqlite</code> 和运行时）</li><li><strong>Node.js</strong> ≥20.0.0（opencode 运行时要求）</li><li><strong>npm</strong> ≥9.0.0（包安装）</li></ul><h2 id="bun-vs-node-js" tabindex="-1">Bun vs Node.js <a class="header-anchor" href="#bun-vs-node-js" aria-label="Permalink to &quot;Bun vs Node.js&quot;">​</a></h2><p>rolebox 核心运行时依赖 <strong>Bun</strong>，但部分子系统和可选功能可兼容 Node.js。</p><h3 id="必须使用-bun-的功能" tabindex="-1">必须使用 Bun 的功能 <a class="header-anchor" href="#必须使用-bun-的功能" aria-label="Permalink to &quot;必须使用 Bun 的功能&quot;">​</a></h3><table tabindex="0"><thead><tr><th>功能</th><th>依赖</th><th>来源</th></tr></thead><tbody><tr><td>持久记忆系统</td><td><code>bun:sqlite</code> (内置 SQLite 引擎)</td><td><code>src/memory/store.ts:3</code>, <code>src/memory/search.ts:1</code>, <code>src/memory/schema.ts:1</code></td></tr><tr><td>构建流程</td><td><code>bun run build</code> (TypeScript 编译 + TUI 构建)</td><td><code>package.json:36</code></td></tr><tr><td>测试运行</td><td><code>bun test</code></td><td><code>package.json:40-41</code></td></tr><tr><td>CLI 开发脚本</td><td><code>bun run scripts/*</code></td><td><code>package.json</code></td></tr></tbody></table><h3 id="可用-node-js-运行的功能" tabindex="-1">可用 Node.js 运行的功能 <a class="header-anchor" href="#可用-node-js-运行的功能" aria-label="Permalink to &quot;可用 Node.js 运行的功能&quot;">​</a></h3><p>以下功能在 Bun 环境下开发验证，但底层依赖均为纯 JavaScript/TypeScript 包，理论上可在 Node.js ≥20.0.0 下运行：</p><table tabindex="0"><thead><tr><th>功能</th><th>说明</th></tr></thead><tbody><tr><td>角色 YAML 加载与解析</td><td>依赖 <code>js-yaml</code> （纯 JS）</td></tr><tr><td>CLI 命令 (init/list/search/update/sync)</td><td>依赖 <code>citty</code> (纯 JS)</td></tr><tr><td>Dispatch 调度系统</td><td>全部为纯 TS 实现</td></tr><tr><td>LSP 集成</td><td>通过 child_process 调用语言服务器</td></tr><tr><td>Hashline 编辑系统</td><td>纯文件 I/O</td></tr><tr><td>web_fetch / web_read</td><td>依赖可选包 (Playwright 在 Node.js 下可用)</td></tr><tr><td>TUI 仪表板</td><td>依赖 Solid.js + OpenTU (跨运行时)</td></tr></tbody></table><blockquote><p>注意：虽然上述功能在 Node.js 下可运行，但 rolebox 官方仅验证 Bun 运行时。在 Node.js 下运行未经完整测试，可能存在未预期的行为差异。建议始终使用 Bun 运行 rolebox。</p></blockquote><h3 id="运行时对比" tabindex="-1">运行时对比 <a class="header-anchor" href="#运行时对比" aria-label="Permalink to &quot;运行时对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>Bun</th><th>Node.js</th></tr></thead><tbody><tr><td>SQLite 支持</td><td>✅ 内置 <code>bun:sqlite</code></td><td>❌ 需额外安装 <code>better-sqlite3</code> 等包</td></tr><tr><td>启动速度</td><td>✅ 快速 (编译缓存)</td><td>⚠️ 较慢</td></tr><tr><td>包管理</td><td>✅ 内置 (bun install)</td><td>✅ npm/pnpm/yarn</td></tr><tr><td>rolebox 官方支持</td><td>✅ 完整支持</td><td>⚠️ 部分支持（未完整验证）</td></tr></tbody></table><blockquote><p>来源：<code>../rolebox/src/memory/store.ts:3</code>, <code>../rolebox/src/memory/search.ts:1</code>, <code>../rolebox/src/memory/schema.ts:1</code> — 确认 <code>bun:sqlite</code> 为内存系统的硬依赖。</p></blockquote><h2 id="已知兼容性边界" tabindex="-1">已知兼容性边界 <a class="header-anchor" href="#已知兼容性边界" aria-label="Permalink to &quot;已知兼容性边界&quot;">​</a></h2><ul><li><strong>无角色继承</strong>：角色之间不支持继承关系，每个角色完全独立</li><li><strong>无运行时角色切换</strong>：会话中途不能更换代理角色</li><li><strong>无跨子代理直接通信</strong>：子代理之间不能直接通信，结果通过父角色传递</li><li><strong>最多 3 级嵌套</strong>：dispatch 支持的嵌套深度上限为 3 级（父 → 子 → 孙）</li></ul><h2 id="从-v0-x-升级指南" tabindex="-1">从 v0.x 升级指南 <a class="header-anchor" href="#从-v0-x-升级指南" aria-label="Permalink to &quot;从 v0.x 升级指南&quot;">​</a></h2><p>rolebox 经历了从 v0.1 到 v0.23 的快速迭代，其中部分版本引入了需要关注的变化。</p><h3 id="v0-15-x-→-v0-17-x-核心功能升级" tabindex="-1">v0.15.x → v0.17.x：核心功能升级 <a class="header-anchor" href="#v0-15-x-→-v0-17-x-核心功能升级" aria-label="Permalink to &quot;v0.15.x → v0.17.x：核心功能升级&quot;">​</a></h3><p>这是功能最密集的升级窗口，新增了 LSP 集成（30+ 工具）、会话管理工具套件和 Hashline 编辑系统。升级后需注意：</p><ul><li><strong>opencode 版本要求提升至 ≥1.3.0</strong>（原先 ≥1.0.0）</li><li><strong><code>@opencode-ai/plugin</code> 依赖更新至 <code>^1.3.0</code></strong>（新增 SDK 接口）</li><li>需确保 <code>package.json</code> 中的 <code>peerDependencies</code> 已更新</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 升级命令</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rolebox@latest</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 确认 opencode 版本</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> opencode</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 应 ≥1.3.0</span></span></code></pre></div><h3 id="v0-12-0-状态存储迁移" tabindex="-1">v0.12.0：状态存储迁移 <a class="header-anchor" href="#v0-12-0-状态存储迁移" aria-label="Permalink to &quot;v0.12.0：状态存储迁移&quot;">​</a></h3><p>v0.12.0 将状态存储从 <code>XDG_DATA_HOME</code> <strong>迁移到项目本地 <code>.rolebox/</code> 目录</strong>。如果你从 v0.11.x 或更早版本升级：</p><ul><li>历史会话和调度状态<strong>不会自动迁移</strong>——旧数据保留在原位置</li><li>新会话和调度任务将写入 <code>.rolebox/</code> 目录</li><li>如需保留旧状态数据，手动复制 <code>~/.local/share/rolebox/</code> 的内容到项目 <code>.rolebox/state/</code> 目录</li></ul><h3 id="v0-10-0-dispatch-调度系统重写" tabindex="-1">v0.10.0：Dispatch 调度系统重写 <a class="header-anchor" href="#v0-10-0-dispatch-调度系统重写" aria-label="Permalink to &quot;v0.10.0：Dispatch 调度系统重写&quot;">​</a></h3><p>v0.10.0 对 dispatch 子系统进行了全面重写（事件驱动、并发隔离、状态持久化 v2）：</p><ul><li>旧的全局轮询模式被 <code>TaskWatchdogManager</code> 取代</li><li>引入了 per-model 并发隔离和背压队列</li><li>状态持久化使用新的 schema v3/v4——如果从更早版本升级，旧的 dispatch 状态文件不会被读取</li><li>建议升级后清空旧的状态目录：<code>rm -rf .rolebox/state/</code>（如果存在旧文件）</li></ul><h3 id="v0-5-x-及更早版本-重大架构变更" tabindex="-1">v0.5.x 及更早版本：重大架构变更 <a class="header-anchor" href="#v0-5-x-及更早版本-重大架构变更" aria-label="Permalink to &quot;v0.5.x 及更早版本：重大架构变更&quot;">​</a></h3><ul><li><strong>v0.6.0</strong>：引入 References 和 Collaboration Graph 系统</li><li><strong>v0.10.0</strong>：从简单 dispatch 到事件驱动架构</li><li><strong>v0.15.0</strong>：<code>|loop|</code> 语义重写——每轮循环（包括第一轮）在子工作线程中运行</li><li><strong>v0.17.0</strong>：LSP、会话工具、Hashline 编辑——需要更新 <code>peerDependencies</code></li><li><strong>v0.20.0</strong>：微内核架构、记忆系统、TUI 仪表板——需要 Bun ≥1.1.0</li></ul><blockquote><p>来源：<a href="https://github.com/EricMoin/rolebox/blob/main/CHANGELOG.md" target="_blank" rel="noreferrer">CHANGELOG</a> — 完整的版本历史及各版本的破坏性变更说明。</p></blockquote><div class="tip custom-block"><p class="custom-block-title">升级路径决策树</p><p>根据您当前使用的 rolebox 版本，参考以下升级路径：</p><ul><li>从 <strong>v0.5.x</strong> 升级：需依次关注 v0.6.0（References 系统）→ v0.10.0（Dispatch 重写）→ v0.12.0（状态迁移）→ v0.15.0（Loop 重写）→ v0.17.0（依赖升级）→ v0.20.0（Bun 运行时）</li><li>从 <strong>v0.10.x</strong> 升级：需依次关注 v0.12.0（状态迁移）→ v0.15.0（Loop 重写）→ v0.17.0（依赖升级）→ v0.20.0（Bun 运行时）</li><li>从 <strong>v0.17.x</strong> 升级：需依次关注 v0.20.0（安装 Bun 运行时）→ v0.23.0（TUI 键盘交互变更为鼠标）</li><li>从 <strong>v0.20.x</strong> 升级：直接升级至最新版，注意 v0.23.0 中 TUI 键盘快捷键已变更为 <code>Ctrl+</code> 前缀</li></ul><hr><h2 id="弃用时间线" tabindex="-1">弃用时间线 <a class="header-anchor" href="#弃用时间线" aria-label="Permalink to &quot;弃用时间线&quot;">​</a></h2><p>以下功能已进入弃用路径或已被替代，在版本升级时需关注兼容性变更。</p><table tabindex="0"><thead><tr><th>版本</th><th>弃用项</th><th>替代方案</th><th>状态</th></tr></thead><tbody><tr><td>v0.23.0</td><td>TUI 键盘交互模式</td><td>鼠标交互（Ctrl+ 前缀快捷键）</td><td>已移除（CHANGELOG.md:28）</td></tr><tr><td>v0.22.0</td><td>OpencodeClient 会话接口</td><td>ISessionClient 平台抽象层</td><td>已替换（CHANGELOG.md:62）</td></tr><tr><td>v0.15.0</td><td>LoopManager 顺序状态机</td><td>LoopCoordinator 推链调度</td><td>已替换（CHANGELOG.md:215）</td></tr><tr><td>v0.12.0</td><td>XDG_DATA_HOME 状态存储</td><td>项目本地 .rolebox/ 目录</td><td>已迁移（CHANGELOG.md:302）</td></tr><tr><td>v0.10.0</td><td>全局轮询 Dispatch 模式</td><td>TaskWatchdogManager 事件驱动</td><td>已替换（CHANGELOG.md:316）</td></tr></tbody></table><blockquote><p>以上信息来源于 CHANGELOG.md。处于已替换或已迁移状态的功能在旧版本中仍保留，但后续版本不再维护。建议在升级时参考<a href="#破坏性变更摘要">破坏性变更摘要</a>中的操作指引。</p></blockquote></div><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/rolebox-docs/03-Reference/limitations.html">已知限制</a> — 完整的功能限制列表</li><li><a href="/rolebox-docs/02-Guide/subagents.html">子代理</a> — 子代理层级与调度机制</li><li><a href="/rolebox-docs/03-Reference/dispatch-config.html">调度配置</a> — 并发与预算控制</li></ul>`,55)])])}const u=d(a,[["render",l]]);export{b as __pageData,u as default};
